efaultKubeEffectiveVersion returns the MutableEffectiveVersion based on the\n184: // latest K8s release.\n185: func DefaultKubeEffectiveVersion() MutableEffectiveVersion {\n186: \tbinaryVersion := version.MustParse(DefaultKubeBinaryVersion).WithInfo(Get())\n187: \treturn newEffectiveVersion(binaryVersion, false)\n188: }\n189: \n190: // ValidateKubeEffectiveVersion validates the EmulationVersion is equal to the binary version at 1.31 for kube components.\n191: // emulationVersion is introduced in 1.31, so it is only allowed to be equal to the binary version at 1.31.\n192: func ValidateKubeEffectiveVersion(effectiveVersion EffectiveVersion) error {\n193: \tbinaryVersion := version.MajorMinor(effectiveVersion.BinaryVersion().Major(), effectiveVersion.BinaryVersion().Minor())\n194: \tif binaryVersion.EqualTo(version.MajorMinor(1, 31)) \u0026\u0026 !effectiveVersion.EmulationVersion().EqualTo(binaryVersion) {\n195: \t\treturn fmt.Errorf(\"emulation version needs to be equal to binary version(%s) in compatibility-version alpha, got %s\",\n196: \t\t\tbinaryVersion.String(), effectiveVersion.EmulationVersion().String())\n197: \t}\n198: \treturn nil\n199: }\n200: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/kubernetes--v1.32.0@d17b464c6fcd3273e4b1f695890bf0af7d5b272d/-/blob/staging/src/k8s.io/component-base/version/version.go"}", "annotations": null, "meta": null}], "structuredContent": {"content": "1: /*
